340	// rankAndDegradeDiffForReview reorders diff files so that AC-referenced files
341	// appear first, then files matching governing-ref paths, then others; and
342	// degrades any individual file body that exceeds maxInlinedFileBytes to
343	// "stat + hunk headers only" so a single oversize file cannot dominate the
344	// diff section. The returned string is a re-serialized unified diff suitable
345	// for evidence.ClampDiff. FEAT-022 §1.
346	func rankAndDegradeDiffForReview(files []evidence.DiffFile, originalDiff string, b *bead.Bead, refs []GoverningRef, maxInlinedFileBytes int) string {
347		if len(files) == 0 {
348			return originalDiff
349		}
350		rank := func(f evidence.DiffFile) int {
351			if f.Path == "" {
352				return 3
353			}
354			if mentionsPathLike(b.Acceptance, f.Path) {
355				return 0
356			}
357			for _, r := range refs {
358				if pathsRelated(r.Path, f.Path) {
359					return 1
360				}
361			}
362			return 2
363		}
364		ordered := make([]evidence.DiffFile, len(files))
365		copy(ordered, files)
366		sort.SliceStable(ordered, func(i, j int) bool { return rank(ordered[i]) < rank(ordered[j]) })
367	
368		var b2 strings.Builder
369		for _, f := range ordered {
370			body := f.Body
371			if maxInlinedFileBytes > 0 && len(body) > maxInlinedFileBytes {
372				body = degradeDiffFileBody(f)
373			}
374			b2.WriteString(body)
375		}
376		return b2.String()
377	}
